from vex_sdk import VexDetector
from haystack import Pipeline

class AuthFailureDetector(VexDetector):
    def __init__(self):
        super().__init__(name='auth_failures')
        self.failure_count = 0

    def detect(self, inputs, outputs, component_name):
        for output in outputs:
            if hasattr(output, 'meta') and output.meta.get('status_code') in [401, 403]:
                self.failure_count += 1
                self.log_issue(f"Auth failure in {component_name}: {output.meta.get('error')}")
        return self.failure_count > 0

# Usage in pipeline
detector = AuthFailureDetector()
pipeline.add_component('auth_detector', detector)

from vex_sdk import VexScanner
import inspect
from haystack.components import ElasticsearchDocumentStore

class AuthDependencyScanner(VexScanner):
    AUTH_PARAMS = {'api_key', 'token', 'password', 'bearer'}

    def scan_component(self, component):
        sig = inspect.signature(component.__init__)
        missing_auth = []

        for param_name in self.AUTH_PARAMS:
            if param_name not in sig.parameters:
                missing_auth.append(param_name)

        if missing_auth:
            self.log_vulnerability(f'{component.__class__.__name__} missing auth params: {missing_auth}')

scanner = AuthDependencyScanner()
scanner.scan([ElasticsearchDocumentStore, OpenAIChatGenerator])

