from typing import Dict, Any

@component
class AuthMiddleware:
    def __init__(self, api_key: str, base_url: str = None):
        self.api_key = api_key
        self.base_url = base_url

    @component.output_types(retrieved_documents=dict, generated=dict)
    def run(self, query: str, user_role: str = 'user'):
        # Inject auth headers
        headers = {'Authorization': f'Bearer {self.api_key}', 'X-User-Role': user_role}

        return {
            'retrieved_documents': {'query': query, 'headers': headers},
            'generated': {'headers': headers}
        }

