from haystack import component

@component
class RoleBasedFilter:
    def __init__(self):
        self.roles = {'admin': ['*'], 'user': ['public'], 'guest': []}

    @component.input_types(documents=list)
    @component.output_types(filtered_documents=list)
    def run(self, documents: list, user_role: str):
        allowed_types = self.roles.get(user_role, [])

        filtered = [
            doc for doc in documents
            if any(allowed in doc.meta.get('access', '') for allowed in allowed_types)
        ]

        return {'filtered_documents': filtered}

# Add to pipeline after retriever
pipeline.add_component('filter', RoleBasedFilter())
pipeline.connect('retriever', 'filter')
pipeline.connect('filter', 'generator')

